// Flatten the Get Webinars response into one item per webinar.
// VERIFY: response may be a bare array, or { _embedded: { webinars: [...] } }, or { webinars: [...] }.
const resp = $input.first().json;
const list = Array.isArray(resp) ? resp
  : (resp._embedded && resp._embedded.webinars) ? resp._embedded.webinars
  : (resp.webinars || []);

function regionFromText(t) {
  const s = String(t || '').toLowerCase();
  if (/\b(uk|u\.k\.|united kingdom|england|scotland|wales|ireland|irish|dublin)\b/.test(s)) return 'UKI';
  if (/\b(belgium|benelux|luxembourg|brussels)\b/.test(s)) return 'BeLux';
  if (/\b(netherlands|dutch|holland|amsterdam)\b/.test(s)) return 'NL';
  return 'UNASSIGNED';
}

return list.map((w) => {
  // VERIFY field names against your account's payload.
  const start = (w.times && w.times[0] && w.times[0].startTime) || w.startTime || null;
  return { json: {
    event_key: String(w.webinarKey || w.id || ''),
    event_name: w.subject || w.name || null,
    activity_date: start ? String(start).slice(0, 10) : null,
    region_code: regionFromText(w.subject),
    registrants: Number(w.numberOfRegistrants ?? w.registrantCount ?? 0),
    campaign_key: null // optional: map to the SF event campaign later
  }};
}).filter((i) => i.json.event_key && i.json.activity_date);

// Pair each webinar (from Flatten Webinars) with its attendees response (this node's input),
// aligned by index. Attendees count = distinct registrantKey (someone may join multiple sessions).
const webinars = $('Flatten Webinars').all();
const attResp = $input.all();

return webinars.map((wItem, i) => {
  const w = wItem.json;
  const resp = (attResp[i] && attResp[i].json) || [];
  const list = Array.isArray(resp) ? resp
    : (resp._embedded && resp._embedded.attendees) ? resp._embedded.attendees
    : (resp.attendees || []);
  const distinct = new Set(list.map((a) => a.registrantKey || a.attendeeKey || a.email).filter(Boolean));
  return { json: {
    event_key: w.event_key,
    event_name: w.event_name,
    activity_date: w.activity_date,
    region_code: w.region_code,
    campaign_key: w.campaign_key,
    registrants: w.registrants,
    attendees: distinct.size,
    source: 'gotowebinar'
  }};
});
